import java.util.Base64
import javax.servlet.http.HttpServletRequest
import org.w3c.dom.Document
import scala.xml.XML

object ConfigService {
  def parseConfig(xmlString: String): Map[String, String] = {
    try {
      val doc: Document = XML.loadString(xmlString)
      extractSettings(doc)
    } catch {
      case e: Exception => Map.empty
    }
  }

  private def extractSettings(doc: Document): Map[String, String] = {
    val settings = new scala.collection.mutable.HashMap[String, String]()
    for (elem <- doc.elements) {
      if (!elem.attributes.isEmpty) {
        val key = elem.attributes.get("name").get.text
        val value = elem.text
        settings.put(key, value)
      }
    }
    settings.toMap
  }

  def parseConfigFromRequest(req: HttpServletRequest): Map[String, String] = {
    val xmlString = req.getHeader("X-Config")
    if (xmlString != null) {
      parseConfig(xmlString)
    } else {
      Map.empty
    }
  }
